#The below is a script used to generate the energy functions for this energy

def membrane_neo_hookean_energy_density_F(F00, F01, F10, F11, F20, F21, mu, lam, vol):
    F = sp.Matrix([[F00, F01], [F10, F11], [F20, F21]])
    C = F.T @ F
    J = sp.sqrt(sp.det(C))
    psi = mu/2 * (sp.trace(C) - 2) + mu * (1 - J) + lam/2 * (J - 1)**2
    return psi
import sympy as sp
# Define symbols
F00, F01, F10, F11, F20, F21, mu, lam, vol = sp.symbols('F00 F01 F10 F11 F20 F21 mu lam vol')

# # Compute energy
# psi = membrane_energy_element(F00, F01, F10, F11, F20, F21, mu, lam)
psi = membrane_neo_hookean_energy_density_F(F00, F01, F10, F11, F20, F21, mu, lam, vol)



# Compute gradient with respect to F components
gradient = [
    sp.diff(psi, F00).simplify(),
    sp.diff(psi, F01).simplify(),
    sp.diff(psi, F10).simplify(),
    sp.diff(psi, F11).simplify(),
    sp.diff(psi, F20).simplify(),
    sp.diff(psi, F21).simplify(),
]

# # Print gradient as a Python list that can be copy-pasted into a function (all on one line)
gradient_str = "[" + ", ".join([str(gradient[i]) for i in range(6)]) + "]"
print("gradient = ", gradient_str)


# Compute Hessian with respect to F components (4x4 matrix for F00, F01, F10, F11)
F_vars = [F00, F01, F10, F11, F20, F21]
hessian = sp.Matrix([[sp.diff(psi, F_vars[i], F_vars[j]).simplify() for j in range(6)] for i in range(6)])

# Print Hessian as a Python list that can be copy-pasted into a function
